import java.util.*;class P1{static String[][] calc(double[][] a){String[][] r=new String[10][4];for(int i=0;i<10;i++){double w=a[i][0],h=a[i][1]/100;double bmi=w/(h*h);String s=bmi<18.5?"Underweight":bmi<25?"Normal":bmi<30?"Overweight":"Obese";r[i][0]=String.valueOf(a[i][1]);r[i][1]=String.valueOf(w);r[i][2]=String.format("%.2f",bmi);r[i][3]=s;}return r;}public static void main(String[] x){Scanner s=new Scanner(System.in);double[][] a=new double[10][2];for(int i=0;i<10;i++){a[i][0]=s.nextDouble();a[i][1]=s.nextDouble();}String[][] r=calc(a);for(int i=0;i<10;i++)System.out.println(r[i][0]+" "+r[i][1]+" "+r[i][2]+" "+r[i][3]);}}